24	// This is used both as a key and in lookups.
25	type TemplateDescriptor struct {
26		// Group 1.
27		Kind               string // page, home, section, taxonomy, term (and only those)
28		LayoutFromTemplate string // list, single, all,mycustomlayout
29		LayoutFromUser     string //  custom layout set in front matter, e.g. list, single, all, mycustomlayout
30	
31		// Group 2.
32		OutputFormat string // rss, csv ...
33		MediaType    string // text/html, text/plain, ...
34	
35		SitesHash uint64
36	
37		Variant1 string // contextual variant, e.g. "link" in render hooks."
38		Variant2 string // contextual variant, e.g. "id" in render.
39	
40		// Misc.
41		LayoutFromUserMustMatch bool // If set, we only look for the exact layout.
42		IsPlainText             bool // Whether this is a plain text template.
43		AlwaysAllowPlainText    bool // Whether to e.g. allow plain text templates to be rendered in HTML.
44	}
45	
46	func (d *TemplateDescriptor) normalizeFromFile() {
47		if d.LayoutFromTemplate == d.OutputFormat {
48			d.LayoutFromTemplate = ""
49		}
50	
51		if d.Kind == kinds.KindTemporary {
52			d.Kind = ""
53		}
54	
55		if d.LayoutFromTemplate == d.Kind {
56			d.LayoutFromTemplate = ""
57		}
58	}
