48	func (s *TemplateStore) parseTemplate(ti *TemplInfo) error {
49		err := s.tns.doParseTemplate(ti)
50		if err != nil {
51			return s.addFileContext(ti, "parse of template failed", err)
52		}
53		return err
54	}
