56	func (t *templateNamespace) newBlankTemplate(ti *TemplInfo) tpl.Template {
57		if ti.D.IsPlainText {
58			tt, err := t.parseText.New(ti.Name()).Parse("")
59			if err != nil {
60				panic(err)
61			}
62			return tt
63	
64		}
65		tt, err := t.parseHTML.New(ti.Name()).Parse("")
66		if err != nil {
67			panic(err)
68		}
69		return tt
70	}
