143	func (t *templateNamespace) applyBaseTemplate(overlay *TemplInfo, base keyTemplateInfo) error {
144		tb := &TemplWithBaseApplied{
145			Overlay: overlay,
146			Base:    base.Info,
147		}
148	
149		base.Info.overlays = append(base.Info.overlays, overlay)
150	
151		var templ tpl.Template
152		if overlay.D.IsPlainText {
153			tt := texttemplate.Must(t.parseText.Clone()).New(overlay.PathInfo.PathNoLeadingSlash())
154			var err error
155			tt, err = tt.Parse(base.Info.content)
156			if err != nil {
157				return err
158			}
159			tt, err = tt.Parse(overlay.content)
160			if err != nil {
161				return err
162			}
163			templ = tt
164			t.baseofTextClones = append(t.baseofTextClones, tt)
165		} else {
166			tt := htmltemplate.Must(t.parseHTML.CloneShallow()).New(overlay.PathInfo.PathNoLeadingSlash())
167			var err error
168			tt, err = tt.Parse(base.Info.content)
169			if err != nil {
170				return err
171			}
172			tt, err = tt.Parse(overlay.content)
173			if err != nil {
174				return err
175			}
176			templ = tt
177	
178			t.baseofHtmlClones = append(t.baseofHtmlClones, tt)
179	
180		}
181	
182		tb.Template = &TemplInfo{
183			Template: templ,
184			base:     base.Info,
185			PathInfo: overlay.PathInfo,
186			Fi:       overlay.Fi,
187			D:        overlay.D,
188			matrix:   overlay.matrix,
189			noBaseOf: true,
190		}
191	
192		variants := overlay.baseVariants.Get(base.Key)
193		if variants == nil {
194			variants = make(map[TemplateDescriptor]*TemplWithBaseApplied)
195			overlay.baseVariants.Insert(base.Key, variants)
196		}
197		variants[base.Info.D] = tb
198		return nil
199	}
