201	func (t *templateNamespace) templatesIn(in tpl.Template) iter.Seq[tpl.Template] {
202		return func(yield func(t tpl.Template) bool) {
203			switch in := in.(type) {
204			case *htmltemplate.Template:
205				for t := range in.All() {
206					if !yield(t) {
207						return
208					}
209				}
210	
211			case *texttemplate.Template:
212				for t := range in.All() {
213					if !yield(t) {
214						return
215					}
216				}
217			}
218		}
219	}
