221	var baseTemplateDefineRe = regexp.MustCompile(`^{{-?\s*define`)
222	
223	// needsBaseTemplate returns true if the first non-comment template block is a
224	// define block.
225	func needsBaseTemplate(templ string) bool {
226		idx := -1
227		inComment := false
228		for i := 0; i < len(templ); {
229			if !inComment && strings.HasPrefix(templ[i:], "{{/*") {
230				inComment = true
231				i += 4
232			} else if !inComment && strings.HasPrefix(templ[i:], "{{- /*") {
233				inComment = true
234				i += 6
235			} else if inComment && strings.HasPrefix(templ[i:], "*/}}") {
236				inComment = false
237				i += 4
238			} else if inComment && strings.HasPrefix(templ[i:], "*/ -}}") {
239				inComment = false
240				i += 6
241			} else {
242				r, size := utf8.DecodeRuneInString(templ[i:])
243				if !inComment {
244					if strings.HasPrefix(templ[i:], "{{") {
245						idx = i
246						break
247					} else if !unicode.IsSpace(r) {
248						break
249					}
250				}
251				i += size
252			}
253		}
254	
255		if idx == -1 {
256			return false
257		}
258	
259		return baseTemplateDefineRe.MatchString(templ[idx:])
260	}
261	
262	func removeLeadingBOM(s string) string {
263		const bom = '\ufeff'
264	
265		for i, r := range s {
266			if i == 0 && r != bom {
267				return s
268			}
269			if i > 0 {
270				return s[i:]
271			}
272		}
273	
274		return s
275	}
