291	func (t *templateNamespace) createPrototypesParse() error {
292		if t.prototypeHTML == nil {
293			panic("prototypeHTML not set")
294		}
295		t.parseHTML = htmltemplate.Must(t.prototypeHTML.Clone())
296		t.parseText = texttemplate.Must(t.prototypeText.Clone())
297		return nil
298	}
