300	func (t *templateNamespace) createPrototypes(init bool) error {
301		if init {
302			t.prototypeHTML = htmltemplate.Must(t.parseHTML.Clone())
303			t.prototypeText = texttemplate.Must(t.parseText.Clone())
304		}
305	
306		return nil
307	}
