309	func newTemplateNamespace(funcs map[string]any) *templateNamespace {
310		return &templateNamespace{
311			parseHTML:      htmltemplate.New("").Funcs(funcs),
312			parseText:      texttemplate.New("").Funcs(funcs),
313			standaloneText: texttemplate.New("").Funcs(funcs),
314		}
315	}
316	
317	func isText(t tpl.Template) bool {
318		switch t.(type) {
319		case *texttemplate.Template:
320			return true
321		case *htmltemplate.Template:
322			return false
323		default:
324			panic("unknown template type")
325		}
326	}
