35	type siteRenderContext struct {
36		cfg *BuildCfg
37	
38		infol logg.LevelLogger
39	
40		// languageIdx is the zero based index of the site.
41		languageIdx int
42	
43		// Zero based index for all output formats combined.
44		sitesOutIdx int
45	
46		// Zero based index of the output formats configured within a Site.
47		// Note that these outputs are sorted.
48		outIdx int
49	
50		multihost bool
51	}
52	
53	// Whether to render 404.html, robotsTXT.txt and similar.
54	// These are usually rendered once in the root of public.
55	func (s siteRenderContext) shouldRenderStandalonePage(kind string) bool {
56		if s.multihost || kind == kinds.KindSitemap {
57			// 1 per site
58			return s.outIdx == 0
59		}
60	
61		if kind == kinds.KindTemporary || kind == kinds.KindStatus404 {
62			// 1 for all output formats
63			return s.outIdx == 0
64		}
65	
66		// 1 for all sites and output formats.
67		return s.languageIdx == 0 && s.outIdx == 0
68	}
69	
70	// renderPages renders pages concurrently.
71	func (s *Site) renderPages(ctx *siteRenderContext) error {
72		numWorkers := config.GetNumWorkerMultiplier()
73	
74		results := make(chan error)
75		pages := make(chan *pageState, numWorkers) // buffered for performance
76		errs := make(chan error)
77	
78		go s.errorCollator(results, errs)
79	
80		wg := &sync.WaitGroup{}
81	
82		for range numWorkers {
83			wg.Add(1)
84			go pageRenderer(ctx, s, pages, results, wg)
85		}
86	
87		cfg := ctx.cfg
88	
89		w := &doctree.NodeShiftTreeWalker[contentNode]{
90			Tree: s.pageMap.treePages,
91			Handle: func(key string, n contentNode) (radix.WalkFlag, error) {
92				if p, ok := n.(*pageState); ok {
93					if cfg.shouldRender(ctx.infol, p) {
94						select {
95						case <-s.h.Done():
96							return radix.WalkStop, nil
97						default:
98							pages <- p
99						}
100					}
101				}
102				return radix.WalkContinue, nil
103			},
104		}
105	
106		if err := w.Walk(context.Background()); err != nil {
107			return err
108		}
109	
110		close(pages)
111	
112		wg.Wait()
113	
114		close(results)
115	
116		err := <-errs
117		if err != nil {
118			return fmt.Errorf("%v failed to render pages: %w", s.resolveDimensionNames(), err)
119		}
120		return nil
121	}
