123	func pageRenderer(
124		ctx *siteRenderContext,
125		s *Site,
126		pages <-chan *pageState,
127		results chan<- error,
128		wg *sync.WaitGroup,
129	) {
130		defer wg.Done()
131	
132		sendErr := func(err error) bool {
133			select {
134			case results <- err:
135				return true
136			case <-s.h.Done():
137				return false
138			}
139		}
140	
141		for p := range pages {
142	
143			if p.m.isStandalone() && !ctx.shouldRenderStandalonePage(p.Kind()) {
144				continue
145			}
146	
147			if p.m.pageConfig.Build.PublishResources {
148				if err := p.renderResources(); err != nil {
149					if sendErr(p.errorf(err, "failed to render resources")) {
150						continue
151					} else {
152						return
153					}
154				}
155			}
156	
157			if !s.conf.DisableAliases && !s.h.BuildState.IsRebuild() && p.render {
158				of := p.outputFormat()
159				if of.IsHTML && of.Permalinkable {
160					// Render any aliases for this page.
161					if err := s.renderAliasesForPage(p); err != nil {
162						if sendErr(err) {
163							continue
164						} else {
165							return
166						}
167					}
168				}
169			}
170	
171			if !p.render {
172				// Nothing more to do for this page.
173				continue
174			}
175	
176			templ, found, err := p.resolveTemplate()
177			if err != nil {
178				if sendErr(p.errorf(err, "failed to resolve template")) {
179					continue
180				} else {
181					return
182				}
183			}
184	
185			if !found {
186				s.Log.Trace(
187					func() string {
188						return fmt.Sprintf("no layout for kind %q found", p.Kind())
189					},
190				)
191				// Don't emit warning for missing 404 etc. pages.
192				if !p.m.isStandalone() {
193					s.logMissingLayout("", p.Layout(), p.Kind(), p.f.Name)
194				}
195				continue
196			}
197	
198			targetPath := p.targetPaths().TargetFilename
199	
200			s.Log.Trace(
201				func() string {
202					return fmt.Sprintf("rendering outputFormat %q kind %q using layout %q to %q", p.pageOutput.f.Name, p.Kind(), templ.Name(), targetPath)
203				},
204			)
205	
206			var d any = p
207			switch p.Kind() {
208			case kinds.KindSitemapIndex:
209				d = s.h.Sites
210			}
211	
212			if err := s.renderAndWritePage(&s.PathSpec.ProcessingStats.Pages, targetPath, p, d, templ); err != nil {
213				if sendErr(err) {
214					continue
215				} else {
216					return
217				}
218			}
219	
220			if of := p.outputFormat(); p.IsHome() && of.IsHTML && s.isDefault() && (of.Path != "" || of.Name == "html") {
221				if err = s.renderDefaultSiteRedirect(p); err != nil {
222					if sendErr(err) {
223						continue
224					} else {
225						return
226					}
227				}
228			}
229	
230			if p.paginator != nil && p.paginator.current != nil {
231				if err := s.renderPaginator(p, templ); err != nil {
232					if sendErr(err) {
233						continue
234					} else {
235						return
236					}
237				}
238			}
239		}
240	}
